 1	import type { FC, PropsWithChildren } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import SmartLinkify from '@components/common/SmartLinkify';
 5	import type { V1beta1Plan, V1beta1PlanStatusConditions } from '@kubev2v/types';
 6	import {
 7	  Alert,
 8	  AlertVariant,
 9	  Button,
10	  ButtonVariant,
11	  Stack,
12	  Text,
13	  TextContent,
14	  TextVariants,
15	} from '@patternfly/react-core';
16	import { getPlanURL } from '@utils/crds/plans/utils';
17	import { isEmpty } from '@utils/helpers';
18	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
19	
20	type PlanPreserveIPWarningsAlertsProps = PropsWithChildren & {
21	  plan: V1beta1Plan;
22	  conditions: V1beta1PlanStatusConditions[] | undefined;
23	};
24	const PlanPreserveIPWarningsAlerts: FC<PlanPreserveIPWarningsAlertsProps> = ({
25	  conditions,
26	  plan,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	  const navigate = useNavigate();
30	
31	  if (isEmpty(conditions)) return null;
32	
33	  return (
34	    <>
35	      {conditions?.map((condition) => (
36	        <Alert
37	          title={t('The plan migration might not work as expected')}
38	          variant={AlertVariant.warning}
39	        >
40	          <Stack hasGutter>
41	            <TextContent className="forklift-providers-list-header__alert">
42	              <Text component={TextVariants.p}>
43	                <SmartLinkify>{condition?.message ?? ''}</SmartLinkify>
44	                {isEmpty(condition?.items) ? (
45	                  ' '
46	                ) : (
47	                  <ForkliftTrans>
48	                    {' '}
49	                    To troubleshoot, check the{' '}
50	                    <Button
51	                      isInline
52	                      variant={ButtonVariant.link}
53	                      onClick={() => {
54	                        navigate(`${getPlanURL(plan)}/vms`);
55	                      }}
56	                    >
57	                      Virtual machines tab
58	                    </Button>
59	                    .
60	                  </ForkliftTrans>
61	                )}
62	              </Text>
63	            </TextContent>
64	          </Stack>
65	        </Alert>
66	      ))}
67	    </>
68	  );
69	};
70	
71	export default PlanPreserveIPWarningsAlerts;

